import{_ as o,o as e,c as r,a2 as n}from"./chunks/framework.YhErEiPK.js";const h=JSON.parse('{"title":"Why Use Stubborn Contract?","description":"","frontmatter":{},"headers":[],"relativePath":"howto/why-stubborn-contract.md","filePath":"howto/why-stubborn-contract.md"}'),a={name:"howto/why-stubborn-contract.md"};function s(i,t,c,l,u,d){return e(),r("div",null,[...t[0]||(t[0]=[n('<h1 id="why-use-stubborn-contract" tabindex="-1">Why Use Stubborn Contract? <a class="header-anchor" href="#why-use-stubborn-contract" aria-label="Permalink to &quot;Why Use Stubborn Contract?&quot;">​</a></h1><p>Stubborn Contract works great in a polyglot environment. This project has a lot of really interesting features. Quite a few of these features definitely make Stubborn Contract Verifier stand out on the market of Consumer Driven Contract (CDC) tooling. The most interesting features include the following:</p><ul><li><strong>Ability to do CDC with messaging.</strong> Stubborn Contract is not limited to HTTP — it supports messaging protocols such as Kafka, RabbitMQ, and Apache Camel.</li><li><strong>Clear and easy to use, statically typed DSL.</strong> The Groovy DSL provides a clean, type-safe way to express contracts.</li><li><strong>Ability to copy-paste your current JSON file to the contract and edit only its elements.</strong> The YAML contract format is very close to raw JSON/YAML, making migration easy.</li><li><strong>Automatic generation of tests from the defined contract.</strong> On the producer side, Stubborn Contract generates and runs tests automatically.</li><li><strong>Stub Runner functionality.</strong> The stubs are automatically downloaded at runtime from Nexus or Artifactory.</li><li><strong>Spring Cloud integration.</strong> No discovery service is needed for integration tests.</li><li><strong>Ability to add support for any language &amp; framework through Docker.</strong> Polyglot teams can use the Docker image to integrate Stubborn Contract with Node.js, Python, Ruby, and other languages.</li></ul>',3)])])}const b=o(a,[["render",s]]);export{h as __pageData,b as default};
